parameters.jsCode:
const email = $input.item.json;
const fromRaw = email.From || email.from || '';
const from = typeof fromRaw === 'object' ? (fromRaw.value?.[0]?.address || fromRaw.text || JSON.stringify(fromRaw)) : fromRaw;
const subject = email.subject || '';
const body = email.text || email.snippet || '';

const sessionMatch = body.match(/Session ID: ([a-zA-Z0-9\-]+)/);
const sessionId = sessionMatch ? sessionMatch[1] : 'UNKNOWN-' + Date.now();

const hasAttachment = Object.keys($input.item.binary || {}).length > 0;

const emailMatch = from.match(/[\w.+\-]+@[\w\-]+\.[\w.]+/);
const candidateEmail = emailMatch ? emailMatch[0] : '';

if (!candidateEmail) throw new Error('From field value: ' + JSON.stringify(fromRaw));

return [{
  json: {
    sessionId,
    candidateEmail,
    from,
    subject,
    body,
    hasAttachment,
    receivedAt: new Date().toISOString()
  }
}];

const replyData = $('Extract Reply & Session Context').item.json;
const pendingRow = $input.item.json;

if (!pendingRow || !pendingRow['Job Role']) {
  throw new Error('No pending application found for ' + replyData.candidateEmail + '. Either already processed or session expired.');
}

// Build enriched CV content by combining original context with reply
const enrichedContent = `
CANDIDATE FOLLOW-UP REPLY:
===========================
${replyData.replyBody}

ORIGINAL APPLICATION CONTEXT:
==============================
Name: ${pendingRow['Name']}
Email: ${pendingRow['Email']}
Role Applied: ${pendingRow['Role Applied']}
Original Missing Fields: ${pendingRow['Missing Fields']}
Original Completeness Score: ${pendingRow['Completeness Score']}/100
`;

return [{
  json: {
    sessionId: pendingRow['Session ID'] || replyData.sessionId,
    candidateEmail: replyData.candidateEmail,
    candidateName: pendingRow['Name'],
    jobRole: pendingRow['Role Applied'],
    enrichedContent,
    hasAttachment: replyData.hasAttachment,
    isReEvaluation: true,
    replyReceivedAt: replyData.replyReceivedAt
  },
  binary: $('Extract Reply & Session Context').item.binary
}];

const resp = $input.item.json;
const content = resp.output?.[0]?.content?.[0]?.text || '';
if (!content) throw new Error('OpenAI re-evaluation returned no content');

let parsed;
try {
  const cleaned = content.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  throw new Error('Failed to parse re-eval JSON: ' + content.substring(0, 200));
}

const ctx = $('Merge Reply with Original Context').item.json;
parsed._sessionId = ctx.sessionId;
parsed._jobRole = ctx.jobRole;
parsed._candidateEmail = ctx.candidateEmail;
parsed._candidateName = ctx.candidateName;
parsed._isReEvaluation = true;
parsed._processedAt = new Date().toISOString();

return [{ json: parsed }];
